	if flag.Type != flipt.FlagType_BOOLEAN_FLAG_TYPE {
		s.tracker.RecordEvaluation()
		s.tracker.RecordError()
		return nil, errs.ErrInvalidf("flag type %s invalid", flag.Type)
	}

	resp, err := s.boolean(ctx, flag, r)
	s.tracker.RecordEvaluation()
	if err != nil {
		s.tracker.RecordError()
		return nil, err
	}

	if resp.Reason == rpcevaluation.EvaluationReason_MATCH_EVALUATION_REASON {
		s.tracker.RecordMatch()
